// Assemble final HTML pages from src/layout.html + src/pages/*.html
import fs from "node:fs";
import path from "node:path";
import crypto from "node:crypto";

const R = process.cwd();
const layout = fs.readFileSync(path.join(R, "src/layout.html"), "utf8");

// asset version (content hash of css+js) for cache-busting
const hashSrc = fs.readFileSync(path.join(R, "assets/css/styles.css")) + fs.readFileSync(path.join(R, "assets/js/main.js"));
const V = crypto.createHash("sha1").update(hashSrc).digest("hex").slice(0, 8);

// Portfolio statistics snapshot — generated by tools/fetch_portfolio_map.py from
// GOLD.DP_PortfolioDB (metroAreas comes from the Census-derived tools/msa_cache.json).
// Fallbacks keep the build working if the snapshot is absent.
const STATS_FALLBACK = { currentProperties: 422, totalProperties: 574, states: 40,
  storageUnits: 168966, squareFeet: 24816465, unitsSinceInception: 241139,
  transactions: 356, metroAreas: 120 };
let STATS = STATS_FALLBACK, STATS_ASOF = "";
try {
  const pj = JSON.parse(fs.readFileSync(path.join(R, "assets/data/portfolio.json"), "utf8"));
  STATS = { ...STATS_FALLBACK, ...(pj.stats || {}) };
  STATS_ASOF = pj.generated || "";
} catch { /* no snapshot yet — use fallbacks */ }

const floorTo = (n, step) => Math.floor(n / step) * step;
const num = (n) => Number(n).toLocaleString("en-US");
const fmtAsOf = (iso) => {
  if (!iso) return "December 31, 2025";
  const [y, m, d] = iso.split("-").map(Number);
  return new Date(Date.UTC(y, m - 1, d)).toLocaleDateString("en-US",
    { year: "numeric", month: "long", day: "numeric", timeZone: "UTC" });
};

// Prose figures (rounded down so the "more than / in excess of" hedges stay true).
const STAT_TOKENS = {
  "{{STAT_TOTAL_ROUND}}": num(floorTo(STATS.totalProperties, 5)),
  "{{STAT_TXN_ROUND}}": num(floorTo(STATS.transactions, 5)),
  "{{STAT_UNITS_INCEPTION_ROUND}}": num(floorTo(STATS.unitsSinceInception, 10000)),
  "{{STAT_AS_OF}}": fmtAsOf(STATS_ASOF),
};

// Build the six portfolio stat tiles (exact live counts; K+/M+ floored so "+" is true).
function buildPortfolioStats() {
  const tile = (n, label, suffix) =>
    `          <div class="stat"><span class="stat__num" data-count="${n}"` +
    `${suffix ? ` data-suffix="${suffix}"` : ""}>${num(n)}${suffix || ""}</span>` +
    `<span class="stat__label">${label}</span></div>`;
  return [
    tile(STATS.currentProperties, "Current Properties"),
    tile(STATS.states, "States"),
    tile(Math.floor(STATS.storageUnits / 1000), "Units", "K+"),
    tile(Math.floor(STATS.squareFeet / 1e6), "Square Feet", "M+"),
    tile(STATS.metroAreas ?? 133, "Metropolitan Areas"),
    tile(STATS.totalProperties, "Total Properties"),
  ].join("\n");
}

